    uint32_t item_count;
    stream >> item_count;

    // Check if buffer has enough data for all items
    size_t required_size = 5 + (item_count * sizeof(uint32_t));
    if (adaptor.size() < required_size) {
        return result; // Not enough data for all items
    }

