```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert to little-endian and write
        adaptor.write(sensor_id);

        for (auto& temp : temperatures) {
            auto converted_temp = hexi::endian::conditional_reverse(
                temp, std::endian::native, std::endian::little
            );
            adaptor.write(converted_temp);
        }

        auto converted_pressure = hexi::endian::conditional_reverse(
            pressure, std::endian::native, std::endian::little
        );
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read and convert from little-endian to native
        adaptor.read(sensor_id);

        for (auto& temp : temperatures) {
            float read_temp;
            adaptor.read(read_temp);
            hexi::endian::little_to_native_inplace(read_temp);
            temp = read_temp;
        }

        double read_pressure;
        adaptor.read(read_pressure);
        hexi::endian::little_to_native_inplace(read_pressure);
        pressure = read_pressure;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create buffer and adaptor
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create binary stream and serialize
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData result;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Deserialize the data
    stream.deserialise(result);

    return result;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Extract sensor name using view (null-terminated string)
    info.sensor_name = stream.view();

    // Check bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(&info.sensor_id);

    // Skip remaining data
    stream.skip(stream.size());

    return info;
}
